import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

async function streamWithMetrics(prompt) {
  const t0 = performance.now();
  let ttft = null;
  let tokenCount = 0;

  const stream = client.messages.stream({
    model: "claude-haiku-4-5",
    max_tokens: 512,
    messages: [{ role: "user", content: prompt }],
  });

  stream.on("text", (text) => {
    if (ttft === null) {
      ttft = (performance.now() - t0) / 1000;
    }
    tokenCount += 1;
    process.stdout.write(text);
  });

  await stream.finalMessage();
  const total = (performance.now() - t0) / 1000;
  const decodeTime = total - ttft;
  const tps = tokenCount / decodeTime;

  console.log(`\n\n--- Metrics ---`);
  console.log(`TTFT:       ${ttft.toFixed(3)} s`);
  console.log(`Total:      ${total.toFixed(3)} s`);
  console.log(`Tokens:     ${tokenCount}`);
  console.log(`TPS:        ${tps.toFixed(1)} t/s`);
}

await streamWithMetrics("Explain the transformer attention mechanism in detail.");

import asyncio, anthropic, random, time

client = anthropic.AsyncAnthropic()
# Limit to 5 concurrent calls to stay within rate limits
_sem = asyncio.Semaphore(5)

async def safe_call(prompt: str, retries: int = 3) -> str:
    async with _sem:
        for attempt in range(retries):
            try:
                r = await asyncio.wait_for(
                    client.messages.create(
                        model="claude-haiku-4-5", max_tokens=256,
                        messages=[{"role": "user", "content": prompt}],
                    ),
                    timeout=30.0,  # hard per-call timeout
                )
                return r.content[0].text
            except anthropic.RateLimitError:
                wait = 2 ** attempt + random.uniform(0, 1)
                await asyncio.sleep(wait)
            except asyncio.TimeoutError:
                if attempt == retries - 1:
                    return "[error: timeout]"
        return "[error: rate limit exhausted]"
